+import { $internal } from '../common';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait } from '../trait/types';
+
+let aspectId = 0;
+
+/** A named-free, immutable grouping of traits with non-overlapping fields. */
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Schema;
+    readonly [$internal]: { fields: Map<string, Trait> };
+};
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect)?.[$internal]?.fields;
+}
+
+export function createAspect<const T extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: T
+): Aspect<T> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Map<string, Trait>();
+    for (const trait of traits) {
+        if (isRelation(trait) || trait[$internal].relation) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        if (typeof trait.schema === 'function') {
+            throw new Error('Koota: AoS traits cannot be constituents of an aspect.');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: Aspect traits have an overlapping field: ${field}.`);
+            }
+            fields.set(field, trait);
+        }
+    }
+
+    const schema = Object.freeze(
+        Object.assign({}, ...traits.map((trait) => trait.schema))
+    ) as Schema;
+    return Object.freeze({ id: aspectId++, traits: Object.freeze(traits), schema, [$internal]: { fields } }) as Aspect<T>;
+}
