+type StateGroup = { start: number; count: number; aspect?: Aspect };
+
+function getStateGroups(params: QueryParameter[]): StateGroup[] {
+    const groups: StateGroup[] = [];
+    let cursor = 0;
+    for (const param of params) {
+        if (isAspect(param)) {
+            const count = param.traits.filter((trait) => trait[$internal].type !== 'tag').length;
+            groups.push({ start: cursor, count, aspect: param });
+            cursor += count;
+        } else if (!isModifier(param) && !isRelationPair(param)) {
+            if ((param as Trait)[$internal].type !== 'tag') {
+                groups.push({ start: cursor, count: 1 });
+                cursor++;
+            }
+        }
+    }
+    return groups;
+}
+
+function formatState(state: any[], groups: StateGroup[]) {
+    if (!groups.some((group) => group.aspect)) return state;
+    return groups.map((group) =>
+        group.aspect ? Object.assign({}, ...state.slice(group.start, group.start + group.count)) : state[group.start]
+    );
+}
+
+function applyFormattedState(state: any[], formatted: any[], groups: StateGroup[]) {
+    if (!groups.some((group) => group.aspect)) return;
+    for (let i = 0; i < groups.length; i++) {
+        const group = groups[i];
+        if (!group.aspect) continue;
+        for (let j = 0; j < group.count; j++) {
